//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String license;
    String repository;
    String funding;
    String main;
    Engines engines;
    Scripts scripts;
    List<String> files;
    List<String> keywords;
    Dependencies dependencies;
    DevDependencies devDependencies;
    Xo xo;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.license,
        required this.repository,
        required this.funding,
        required this.main,
        required this.engines,
        required this.scripts,
        required this.files,
        required this.keywords,
        required this.dependencies,
        required this.devDependencies,
        required this.xo,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        license: json["license"],
        repository: json["repository"],
        funding: json["funding"],
        main: json["main"],
        engines: Engines.fromJson(json["engines"]),
        scripts: Scripts.fromJson(json["scripts"]),
        files: List<String>.from(json["files"].map((x) => x)),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        dependencies: Dependencies.fromJson(json["dependencies"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        xo: Xo.fromJson(json["xo"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "license": license,
        "repository": repository,
        "funding": funding,
        "main": main,
        "engines": engines.toJson(),
        "scripts": scripts.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "dependencies": dependencies.toJson(),
        "devDependencies": devDependencies.toJson(),
        "xo": xo.toJson(),
    };
}

class Dependencies {
    String ansiStyles;
    String supportsColor;

    Dependencies({
        required this.ansiStyles,
        required this.supportsColor,
    });

    factory Dependencies.fromJson(Map<String, dynamic> json) => Dependencies(
        ansiStyles: json["ansi-styles"],
        supportsColor: json["supports-color"],
    );

    Map<String, dynamic> toJson() => {
        "ansi-styles": ansiStyles,
        "supports-color": supportsColor,
    };
}

