class Rules {
    String unicornPreferStringSlice;
    String unicornPreferIncludes;
    String typescriptEslintMemberOrdering;
    String noRedeclare;
    String unicornStringContent;
    String unicornBetterRegex;

    Rules({
        required this.unicornPreferStringSlice,
        required this.unicornPreferIncludes,
        required this.typescriptEslintMemberOrdering,
        required this.noRedeclare,
        required this.unicornStringContent,
        required this.unicornBetterRegex,
    });

    factory Rules.fromJson(Map<String, dynamic> json) => Rules(
        unicornPreferStringSlice: json["unicorn/prefer-string-slice"],
        unicornPreferIncludes: json["unicorn/prefer-includes"],
        typescriptEslintMemberOrdering: json["@typescript-eslint/member-ordering"],
        noRedeclare: json["no-redeclare"],
        unicornStringContent: json["unicorn/string-content"],
        unicornBetterRegex: json["unicorn/better-regex"],
    );

    Map<String, dynamic> toJson() => {
        "unicorn/prefer-string-slice": unicornPreferStringSlice,
        "unicorn/prefer-includes": unicornPreferIncludes,
        "@typescript-eslint/member-ordering": typescriptEslintMemberOrdering,
        "no-redeclare": noRedeclare,
        "unicorn/string-content": unicornStringContent,
        "unicorn/better-regex": unicornBetterRegex,
    };
}
